import clsx from 'clsx';

import { left as leftStyle, magnifier } from './Magnifier.sty.js';
import { Magnifier } from './Magnifier.js';
import { charsFontWidth12pixelsSize400Map } from '../../text-ellipsis/chars-font-width-map.js';
import { calculateWidth } from '../../text-ellipsis/truncate-string.js';
import { useMagnifierPosition } from '../hooks/useMagnifierPosition.js';

export function LeftMagnifier(
  props: Readonly<{
    label: string;
    mouseY: number;
    offset: number;
    chartBounds?: DOMRect;
  }>,
) {
  const { label, mouseY, offset, chartBounds } = props;

  const { magnifierPosition: top, magnifierRef } = useMagnifierPosition(
    mouseY,
    chartBounds?.top ?? 0,
    chartBounds?.bottom ?? 0,
    'vertical',
  );

  const textWidth = Math.ceil(
    calculateWidth(label, charsFontWidth12pixelsSize400Map),
  );

  const left =
    (chartBounds?.left ?? 0) -
    (magnifierRef.current?.clientWidth ?? 0) -
    offset;

  return (
    <Magnifier
      aria-label="left y-axis magnifier"
      ref={magnifierRef}
      className={clsx(magnifier, leftStyle)}
      style={{ top, left, width: `${textWidth}px` }}
    >
      {label}
    </Magnifier>
  );
}
